unknown","valueText":null,"valueTextList":[],"valueNumber":null,"valueBoolean":null,"valueJson":null,"unit":null,"confidence":null,"note":"公的資料を確認したが、現在の一般利用可否または地点固有情報を確定できない。","checkedAt":"2026-07-22","sources":{"supporting":[],"checked":["src-gsi-map","src-jfa-nagasaki-fishing-ports"],"contradicting":[]}},{"id":"funakaratsu-fishing-port:fishable_area","itemKey":"fishable_area","informationState":"researched_unknown","valueText":null,"valueTextList":[],"valueNumber":null,"valueBoolean":null,"valueJson":null,"unit":null,"confidence":null,"note":"公的資料を確認したが、現在の一般利用可否または地点固有情報を確定できない。","checkedAt":"2026-07-22","sources":{"supporting":[],"checked":["src-gsi-map","src-jfa-nagasaki-fishing-ports"],"contradicting":[]}}]}]}'::jsonb; spot jsonb; source jsonb; value jsonb; source_uuid uuid; detail_uuid uuid; rel text; sid text;
begin
 for spot in select * from jsonb_array_elements(payload->'spots') loop
  for source in select * from jsonb_array_elements(spot->'sources') loop
   source_uuid := (substr(md5(source->>'id'),1,8)||'-'||substr(md5(source->>'id'),9,4)||'-'||substr(md5(source->>'id'),13,4)||'-'||substr(md5(source->>'id'),17,4)||'-'||substr(md5(source->>'id'),21,12))::uuid;
   insert into public.fishing_spot_detail_sources(id,source_type,source_name,source_url,checked_on,note) values(source_uuid,source->>'sourceType',source->>'sourceName',source->>'sourceUrl',(source->>'checkedOn')::date,source->>'note') on conflict(id) do nothing;
  end loop;
  for value in select * from jsonb_array_elements(spot->'values') loop
   detail_uuid := (substr(md5(value->>'id'),1,8)||'-'||substr(md5(value->>'id'),9,4)||'-'||substr(md5(value->>'id'),13,4)||'-'||substr(md5(value->>'id'),17,4)||'-'||substr(md5(value->>'id'),21,12))::uuid;
